head.script:
scwin.initData = {
	"valInfo" : [
		{id : "setcscNm", maxLength : 40, mandatory : true},
		{id : "eqpCpcty", maxLength : 100, mandatory : true},
		{id : "ordgTit", maxByteLength : 4000, mandatory : true, name : "계약명"},
		//{id : "dsuseDtlCtnt", maxByteLength : 4000, mandatory : true},
	],
	"ecctcList" : ["D0110", "D0210", "D0220", "D0310"]
};

/**
 * 팝업 클로즈시 화면 회색처리를 해제한다.
 * @param
 * @return
 */
scwin.onpageunload = function() {
	if (document.getElementById("_modal").style.display == "block") {
		document.getElementById("_modal").style.display = "none";
	}
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSME2000000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	//사업진행구분 코드 설정 + // 화면 데이터 조회
	scwin.initDataSet();
	// 상세보기폼 변경
	scwin.btnInputModal_onclick(false);
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	var thsYear = Number(utilLib.getCurrentDate("yyyy"));
	var preYear = Number(utilLib.getCurrentDate("yyyy")) - 1;
	var params = $p.getParameter("param");
	if (params && params.year) {
		thsYear = params.year;
		preYear = thsYear;
	}
	dmaSearchParam.set("strtDt", String(preYear));
	dmaSearchParam.set("endDt", String(thsYear));
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("setcscCd", "ALL");
	dmaSearchParam.set("chrgDeptCd", "ALL");
	dmaSearchParam.set("prgsSttusCd", "ALL");
};

/**
 * 사업진행구분 코드를 조회 및 세팅한다.
 * @param
 * @return
 */
scwin.initDataSet = function() {
	var requestData = {
		dmaInqireParam : {
			useYn : "Y",
			clsCd : "ECS_2000"
		}
	};

	var option = {
		action : "zz/cmmncd/retrieveCmmnCd.do",
		reqData : requestData,
		resData : dltCmmnCdList,
		success : "scwin.ecctcCdcallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
}

scwin.ecctcCdcallback = function() {
	scwin.setCmmnCdTitle();
};

scwin.setCmmnCdTitle = function() {
	scwin.initData.ecctcList = [];
	var dataList = dltCmmnCdList.getAllJSON();

	for (data of dataList) {
		var obj = {};
		if (data.cmmnCd.substr(0, 1) == "D") {
			scwin.initData.ecctcList.push(data.cmmnCd);
		}
	}

	scwin.initData.ecctcList.forEach(ecsBsnsPrgsDivCd => {
		var titleComp = $p.getComponentById(document.querySelector("#" + $p.getFrameId() + " svg[id$='" + ecsBsnsPrgsDivCd + "']").id);
		var text = dataList.filter(x=> x.cmmnCd == ecsBsnsPrgsDivCd)[0].cmmnCdNm;
		var textX = 430;
		text = text.split("-");
		titleComp.setLabelTitleText(text[0], "", "", text[1]);
		var len = text[2].length;
		if (len > 12) {
			if (text[2].includes("및")) {
				var textTop = text[2].slice(0, text[2].indexOf("및") + 1);
				var textBottom = text[2].slice(text[2].indexOf("및") + 2);
				len = textTop.replaceAll(" ", "").length;
				textX = textX - (len * 20);
				titleComp.setLabelText(textTop, textX, 100, textBottom);
			} else {
				len = text[2].replaceAll(" ", "").length;
				textX = textX - (len * 20);
				titleComp.setLabelText(text[2], textX, 100);
			}
		} else {
			len = text[2].replaceAll(" ", "").length;
			textX = textX - (len * 20);
			titleComp.setLabelText(text[2], textX, 100);
		}
	});
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
}

/**
 * 화면 초기화에 필요한 로직을 수행한다. (조회 및 신규버튼 클릭 시)
 * @param
 * @return
 */
scwin.clearScreen = function() {
	scwin.btnInputModal_onclick(false);
	grdSetcscDsusePrcsDtlHistList.removeFocusedCell();
	scwin.grdFocusedRowIndex = null;

	for (var ecsBsnsPrgsDivCd of scwin.initData.ecctcList) {
		// 상세 사업추진절차 데이터 초기화
		$p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List").removeAll();
		// 상세 사업추진절차 진행사항 초기화
		var titleComp = $p.getComponentById(document.querySelector("#" + $p.getFrameId() + " svg[id$='" + ecsBsnsPrgsDivCd + "']").id);
		titleComp.cleanLabelTitleProcess();
	}

	// 체크박스 초기화
	scwin.chkClear();
};

/**
 * 조회 버튼 클릭 이벤트
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	scwin.clearScreen();
	scwin.inqire();
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.inqire = function() {
	var strtDate = dmaSearchParam.get("strtDt");
	var endDate = dmaSearchParam.get("endDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscCd = dmaSearchParam.get("setcscCd");
	var ecsChrgDeptId = dmaSearchParam.get("chrgDeptCd");
	var prgsSttusCd = dmaSearchParam.get("prgsSttusCd");

	if (String(strtDate).length != 4 || String(endDate).length != 4) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	} else if (utilLib.minusYears(strtDate, endDate) > 15 ? true : false) {
		// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
		alert(utilLib.getMessage("ECS.INFO.00012", "15년")[0]);
		return;
	} else if (parseInt(strtDate) > parseInt(endDate)) {
		// 시작년이 종료년보다 클수 없습니다.
		alert(utilLib.getMessage("ECS.INFO.00015")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
	queryString += `&prgsSttusCd=${prgsSttusCd}`;

	var option = {
		action : "me/dsuse/retrieve-dsuse.do"
			+ queryString,
		method : "get",
		resData : dltSetcscDsusePrcsDtlHistList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	spnTotalRow.setValue(dltSetcscDsusePrcsDtlHistList.getRowCount());

	if (scwin.grdFocusedRowIndex != null) {
		grdSetcscDsusePrcsDtlHistList.setFocusedCell(scwin.grdFocusedRowIndex, 0);
	} else {
		// 화면 오픈과 동시에 상세보기 항목은 초기화 한다.
		scwin.btnNew_onclick();
	}
};

/**
 * 신규버튼 클릭시 dataMap을 초기화 한다.
 * @param
 * @return
 */
scwin.btnNew_onclick = function() {
	scwin.clearScreen();
	dmaSetcscDsusePrcsDtlHist.setEmpty();
	scwin.setModalDisabled(dmaSetcscDsusePrcsDtlHist.getJSON());
	ecsLib.validateInput(grpDtl, scwin.initData.valInfo, true);
};

/**
 * 셀을 선택시 해당 내용을 상세내역으로 표출한다.
 * @param <Int> row
 * @param <Int> col
 * @return
 */
scwin.grdSetcscDsusePrcsDtlHistList_onrowindexchange = function(row, oldRow) {
	scwin.acbClerar();
	scwin.grdFocusedRowIndex = row;
	var rowData = dltSetcscDsusePrcsDtlHistList.getRowJSON(scwin.grdFocusedRowIndex);

	dmaSetcscDsusePrcsDtlHist.setJSON(rowData);
	dmaSetcscDsusePrcsDtlHistOld.setJSON(rowData);
	scwin.setModalDisabled(rowData);
	ecsLib.validateInput(grpDtl, scwin.initData.valInfo, true);

	//상세보기 입력폼 전환
	if(rowData.cmsBsnsCd && rowData.cmsPrjctCd && rowData.cmsPrjctSqncIdtfr) {
		scwin.btnInputModal_onclick(false);
	} else {
		scwin.btnInputModal_onclick(true);
	}

	//상세 사업추진절차 데이터 초기화
	for (var ecsBsnsPrgsDivCd of scwin.initData.ecctcList) {
		$p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List").removeAll();
		$p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List").reform();
	}

	// 상세 사업추진절차 조회
	var queryString = `?dsuseEsntlId=${rowData.dsuseEsntlId}`;

	var option = {
		action : "zz/cmmn/retrieve-ectcc.do"
			+ queryString,
		method : "get",
		resData : "",
		success : "scwin.inqireEctccCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 상세 사업추진절차 체크를 초기화한다.
 * @param
 * @return
 */
scwin.chkClear = function() {
	for (var idx = 1; idx < scwin.initData.ecctcList.length; idx++) {
		$p.getComponentById("chkPassYn" + (idx)).setValue("N");
		//$p.getComponentById("chkPassYn" + (idx)).setDisabled(false);
	}
};

/**
 * 상세 사업추진절차 데이터(생략,완료) 체크를 선택한다..
 * @param
 * @return
 */
scwin.chkDataChecked = function() {
	var ecctcList = scwin.initData.ecctcList;
	for (var idx = 1; idx < ecctcList.length; idx++) {
		var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[idx] + "List").getAllJSON();
		if (grdData.find(obj => obj.ectccId == " ")) {
			$p.getComponentById("chkPassYn" + (idx)).setValue("Y");
		}
	}
};

/**
 * 상세 사업추진절차 inqireEctccCallback 실행한다.
 * @param
 * @return
 */
scwin.inqireEctccCallback = function(resBody) {
	if (resBody.message.code == "success") {
		// 체크박스 초기화
		scwin.chkClear();

		var ecctcList = scwin.initData.ecctcList;
		var dataList = resBody.data;
		var obj = {};
		// obj, 사업추진절차 초기화
		for (var ecsBsnsPrgsDivCd of ecctcList) {
			obj[ecsBsnsPrgsDivCd] = [];
			$p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List").removeAll();
		}

		for (var data of dataList) {
			obj[data.ecsBsnsPrgsDivCd].push(data); 
		}

		var bFlag = true;
		var fill = "#8E8E8E";
		[...ecctcList].reverse().forEach(ecsBsnsPrgsDivCd => {
			var dltData = $p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List");
			var titleComp = $p.getComponentById(document.querySelector("#" + $p.getFrameId() + " svg[id$='" + ecsBsnsPrgsDivCd + "']").id);
			titleComp.cleanLabelTitleProcess();
			if (!bFlag) {
				// 상세 사업추진절차 라벨 색설정
				titleComp.setLabelTitleProcess(bFlag);
				// 체크 박스 설정
				var idx = ecctcList.indexOf(ecsBsnsPrgsDivCd);
				if (!obj[ecsBsnsPrgsDivCd].length) {
					if (idx != 0) {
						$p.getComponentById("chkPassYn" + (idx)).setValue("Y");
						//$p.getComponentById("chkPassYn" + (idx)).setDisabled(true);
					}
				}
			}
			if (obj[ecsBsnsPrgsDivCd].length > 0) {
				dltData.setJSON(obj[ecsBsnsPrgsDivCd]);
				if (bFlag) {
					// 상세 사업추진절차 라벨 블링크
					titleComp.setLabelTitleProcess(bFlag, true);
					bFlag = false;
				}
			}
		});

		// 체크박스 설정
		scwin.chkDataChecked();
	}
};

/**
 * 모달 버튼 숨김 기능 처리
 * @param json : dma.getJSON()
 * @return
 */
scwin.setModalDisabled = function(json) {
	// 모달 버튼 숨김 기능 처리
	if (json.ordgTit != "null" && json.ordgTit != "") {
		btnModal.setStyle("display", "none");
		btnEditModal.setStyle("display", "inline-block");
	} else if (json.ordgTit == "") {
		btnModal.setStyle("display", "inline-block");
		btnEditModal.setStyle("display", "none");
	}
};

/**
 * 상세보기에 기재한 내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	if(ecsLib.validateInput(grpDtl, scwin.initData.valInfo)) {
		if (!ecsLib.isObjEqual(dmaSetcscDsusePrcsDtlHist.getJSON(), dmaSetcscDsusePrcsDtlHistOld.getJSON()) &&
		dmaSetcscDsusePrcsDtlHist.getJSON().ordgTit) {
			// 저장 하시겠습니까? \n수정사유를 입력하세요.
			ecsLib.saveRsn($p, `${dmaSetcscDsusePrcsDtlHist.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00321")[0], "scwin.saveConfirmCallback");
		} else {
			// 저장 하시겠습니까?
			comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321")[0], "scwin.saveConfirmCallback");
		}
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var requestData = {};
	//requestData.dmaSetcscDsusePrcsDtlHist = dmaSetcscDsusePrcsDtlHist.getModifiedJSON();
	requestData.dmaSetcscDsusePrcsDtlHist = dmaSetcscDsusePrcsDtlHist.getJSON();
	requestData.dmaSetcscDsusePrcsDtlHistOld = dmaSetcscDsusePrcsDtlHistOld.getJSON();

	var option = {
		action : "me/dsuse/save-dsuse.do",
		reqData : requestData,
		success : "scwin.saveProcess",
		savedToken : true,
		isShowMeg : false
	};
	if (!ecsLib.isObjEqual(dmaSetcscDsusePrcsDtlHist.getJSON(), dmaSetcscDsusePrcsDtlHistOld.getJSON()) &&
		dmaSetcscDsusePrcsDtlHist.getJSON().ordgTit) {
		ajaxLib.executeAjax($p, option);
	} else {
		// 프로세스 수정/저장 확인 및 실행
		scwin.saveProcess();
	}
};

/**
 * 프로세스 수정/저장 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveProcess = function(resBody) {
	// 신규 등록
	if (!dmaSetcscDsusePrcsDtlHist.getJSON().dsuseEsntlId) {
		scwin.saveMsgCallback(resBody);
	} else {
		var ecctcList = scwin.initData.ecctcList;
		var requestData = {};
		dltEctccList.setJSON([], false);

		var bDummyData = false;
		for (ecctc of [...ecctcList].reverse()) {
			var list = $p.getComponentById("dltEctccLnk" + ecctc + "List").getModifiedJSON();
			var tempList = list.filter(obj => list.filter(innerObj => obj.rowStatus == "C" && innerObj.rowStatus == "E" && obj.ectccId == innerObj.ectccId).length).flatMap(obj => obj.ectccId);
			list = list.filter(obj => !tempList.includes(obj.ectccId));

			list.forEach((obj, idx) => {
				var newIdx = dltEctccList.insertRow();
				dltEctccList.setRowJSON(newIdx, obj, true);
				dltEctccList.modifyRowStatus(newIdx, obj.rowStatus);
			});

			// 현재 프로세스에 데이터가 있다면 이후 빈 프로세스에 빈 문서 생성 
			if ($p.getComponentById("dltEctccLnk" + ecctc + "List").getAllJSON().length) {
				bDummyData = true;
			}

			if (bDummyData) {
				if (!$p.getComponentById("dltEctccLnk" + ecctc + "List").getAllJSON().length) {
					var str = "폐기생략";
					var lnkEsntlId = dmaSetcscDsusePrcsDtlHist.getJSON().dsuseEsntlId;
					var drftDe = "";

					var dummyData = {
						ecsBsnsPrgsDivCd : ecctc,
						ectccId : " ",
						ectccTit : str,
						drftDe : scwin.ecctcDraftDeSelector(ecctcList.indexOf(ecctc)),
						lnkEsntlId : lnkEsntlId,
						rowStatus : "C"
					};

					var newIdx = dltEctccList.insertRow();
					dltEctccList.setRowJSON(newIdx, dummyData, true);
					dltEctccList.modifyRowStatus(newIdx, dummyData.rowStatus);
				}
			}

			/*
			//데이터가 없고 체크가 되어 있다면 빈 문서 생성
			var ecctcIdx = scwin.initData.ecctcList.indexOf(ecctc);
			var lastIdx = scwin.initData.ecctcList.length - 1;
			var str = "폐기생략";

			if (ecctcIdx < lastIdx) {
				str = "폐기진행";
			} else if (ecctcIdx == lastIdx) {
				str = "폐기완료";
			}

			var dummyData = {
				ecsBsnsPrgsDivCd : ecctc,
				ectccId : " ",
				ectccTit : str,
				drftDe : utilLib.getCurrentDate("yyyyMMdd"),
				lnkEsntlId : dmaSetcscDsusePrcsDtlHist.getJSON().dsuseEsntlId,
				rowStatus : "C"
			};

			if (ecctcIdx) {
				if (!$p.getComponentById("dltEctccLnk" + ecctc + "List").getAllJSON().length 
						&& $p.getComponentById("chkPassYn" + (ecctcIdx)).getValue() == "Y") {
					var newIdx = dltEctccList.insertRow();
					dltEctccList.setRowJSON(newIdx, dummyData, true);
					dltEctccList.modifyRowStatus(newIdx, dummyData.rowStatus);
				}
			}
			*/

			/*
			// 폐기 완료 - 데이터가 없고 체크가 되어 있다면 빈 문서 생성.
			var lastIdx = scwin.initData.ecctcList.length - 1;
			if(ecctc == scwin.initData.ecctcList[lastIdx]) {
				if (!$p.getComponentById("dltEctccLnk" + ecctc + "List").getAllJSON().length 
						&& $p.getComponentById("chkPassYn" + (lastIdx)).getValue() == "Y") {
					var dummyData = {
						ecsBsnsPrgsDivCd : ecctc,
						ectccId : " ",
						ectccTit : "폐기완료",
						lnkEsntlId : dmaSetcscDsusePrcsDtlHist.getJSON().dsuseEsntlId,
						rowStatus : "C"
					}
					var newIdx = dltEctccList.insertRow();
					dltEctccList.setRowJSON(newIdx, dummyData, true);
					dltEctccList.modifyRowStatus(newIdx, dummyData.rowStatus);
				}
			}
			*/
		}
		requestData.dltEctccList = dltEctccList.getAllJSON();

		if (dltEctccList.getAllJSON().length) {
			var option = {
				action : "/zz/cmmn/process-ectcc.do",
				reqData : requestData,
				success : "scwin.saveMsgCallback",
				savedToken : true,
				isShowMeg : false
			};
			ajaxLib.executeAjax($p, option);
		} else if (resBody) {
			scwin.saveMsgCallback(resBody);
		} else {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		}
	}
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveMsgCallback = function(resBody) {
	comLib.alert($p, resBody.message.code_name);

	scwin.inqire();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
