/**
 * 상세 사업추진절차 문서를 완료(추가)한다.
 * @param 
 * @return
 */
scwin.btnCmp_onclick = function(idx) {
	var ecctcList = scwin.initData.ecctcList;
	var dltEctccList = $p.getComponentById($p.id + "dltEctccLnk" + ecctcList[idx] + "List");
	var str = "폐기완료";
	var lnkEsntlId = dmaSetcscDsusePrcsDtlHist.getJSON().dsuseEsntlId;
	var drftDe = dmaSetcscDsusePrcsDtlHist.getJSON().lastCompetDe || scwin.ecctcDraftDeSelector(idx);

	if (!lnkEsntlId) {
		// 선택된 자료가 없습니다.
		return comLib.alert($p, utilLib.getMessage("SCM.INFO.00258")[0]);
	} else if (idx >= ecctcList.indexOf("C0110") && !lnkEsntlId) {
		// 등록된 폐기정보가 없습니다.
		return comLib.alert($p, utilLib.getMessage("ECS.INFO.00201")[0].replace("{0}","폐기"));
	}

	if (dltEctccList.getAllJSON().length) {
		// {0} 자료(이)가 존재합니다.
		return comLib.alert($p, utilLib.getMessage("SCM.INFO.00044", "")[0]);
	} else {
		var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[0] + "List").getAllJSON().length;
		if (!grdData) {
			// 폐기수립 사업추진절차 문서등록이 필요합니다.
			return comLib.alert($p, utilLib.getMessage("ECS.INFO.00203")[0].replace("{0}", "폐기수립"));
		}
		var dummyData = {
			ecsBsnsPrgsDivCd : ecctcList[idx],
			ectccId : " ",
			ectccTit : str,
			drftDe : drftDe,
			lnkEsntlId : lnkEsntlId,
			rowStatus : "C"
		};

		var newIdx = dltEctccList.insertRow();
		dltEctccList.setRowJSON(newIdx, dummyData, true);
	}
};

