/**
 * 폐기 상세보기 수기등록 버튼 클릭시 입력폼으로 전환한다.
 * @param bool (true : inputType, false : viewType)
 * @return
 */
scwin.btnInputModal_onclick = function(bool) {
	var viewList =  document.querySelectorAll(".view");
	var inputList = document.querySelectorAll(".input");

	if (!bool) {
		// viewType
		for (view of viewList) {
			view.style.display = "inline-block";
		}
		for (input of inputList) {
			input.style.display = "none";
		}
	} else {
		// inputType
		for (view of viewList) {
			view.style.display = "none";
		}
		for (input of inputList) {
			input.style.display = "inline-block";
		}

		var basinNm = dmaSetcscDsusePrcsDtlHist.getJSON().basinNm;
		var lnrtrDivNm = dmaSetcscDsusePrcsDtlHist.getJSON().lnrtrDivNm;
		var bsnsDivNm = dmaSetcscDsusePrcsDtlHist.getJSON().bsnsDivNm;
		var bsnsMngdeptNm = dmaSetcscDsusePrcsDtlHist.getJSON().bsnsMngdeptNm;
		var edptNm = dmaSetcscDsusePrcsDtlHist.getJSON().edptNm;
		var prjctDivNm = dmaSetcscDsusePrcsDtlHist.getJSON().prjctDivNm;

		basinNm = dltAutoCondition1.getAllJSON().find(obj => obj.cmmnCdNm.includes(basinNm.substr(0, 1)) == true)?.cmmnCd;
		acbBasinNm.setValue(basinNm);
		lnrtrDivNm = dltAutoCondition5.getAllJSON().find(obj => obj.cmmnCdNm == lnrtrDivNm)?.cmmnCd;
		acbLnrtrDivNm.setValue(lnrtrDivNm);
		bsnsDivNm = dltAutoCondition6.getAllJSON().find(obj => obj.cmmnCdNm == bsnsDivNm)?.cmmnCd;
		acbBsnsDivNm.setValue(bsnsDivNm);
		bsnsMngdeptNm = dltAutoCondition7.getAllJSON().find(obj => obj.cmmnCdNm == bsnsMngdeptNm)?.cmmnCd;
		acbBsnsMngdeptNm.setValue(bsnsMngdeptNm);
		edptNm = dltAutoCondition7.getAllJSON().find(obj => obj.cmmnCdNm == edptNm)?.cmmnCd;
		acbEdptNm.setValue(edptNm);
		prjctDivNm = dltAutoCondition8.getAllJSON().find(obj => obj.cmmnCdNm == prjctDivNm)?.cmmnCd;
		acbPrjctDivNm.setValue(prjctDivNm);

		dmaSetcscDsusePrcsDtlHist.setJSON({
			cmsBsnsCd : "",
			cmsPrjctCd : "",
			cmsPrjctSqncIdtfr : "",
			basinNm : basinNm,
			lnrtrDivNm : lnrtrDivNm,
			bsnsDivNm : bsnsDivNm,
			bsnsMngdeptNm : bsnsMngdeptNm,
			edptNm : edptNm,
			prjctDivNm : prjctDivNm
		});
		dmaSetcscDsusePrcsDtlHistOld.setJSON({
			//cmsBsnsCd : "",
			//cmsPrjctCd : "",
			//cmsPrjctSqncIdtfr : "",
			basinNm : basinNm,
			lnrtrDivNm : lnrtrDivNm,
			bsnsDivNm : bsnsDivNm,
			bsnsMngdeptNm : bsnsMngdeptNm,
			edptNm : edptNm,
			prjctDivNm : prjctDivNm
		});
	}
};

