		};
		comLib.openPopup($p, "ECSUserSearchPopup", url, options);
		//$p.getComponentById($p.getPopupId()).setDisabled(true);
		//$p.getComponentById($p.getFrameId()).setDisabled(true);
	}
};

/**
 * 상세 사업추진절차 생략/완료 시 이전 프로세스 수립일, 착공일 찾기
 * @param info
 * idx : 인덱스
 * lastIdx : 어디까지 찾을지 경계
 * @return 수립일, 착공일
 */
scwin.ecctcDraftDeSelector = function(idx, lastIdx) {
	idx = idx - 1;
	var ecctcList = scwin.initData.ecctcList;
	var dltProcessList = "dltEctccLnk" + ecctcList[idx] + "List";
	var dltData = $p.getComponentById(dltProcessList).getAllJSON();

	if (!lastIdx) {
		// 계획
		if (dltData.length) {
			return dltData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max , 0);
		} else {
			return scwin.ecctcDraftDeSelector(idx);
		}
	} else {
		// 건설
		if (idx < lastIdx) {
			return utilLib.getCurrentDate("yyyyMMdd");
		}
		if (dltData.length) {
			return dltData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max , 0);
		} else {
			return scwin.ecctcDraftDeSelector(idx, lastIdx);
		}
	}
};

/**
 * 상세 사업추진절차 생략/완료 시 전체 프로세스 수립일, 착공일 찾기
 * @param info
 * prgsDivCd : 등록된 프로세스 위치
 * @return 수립일, 착공일
 */
scwin.ecctcDraftDeSelectorAll = function(prgsDivCd) {
	var ecctcList = scwin.initData.ecctcList;
	var ecctcIdx = ecctcList.indexOf(prgsDivCd);
	var lastPlanIdx = ecctcList.filter(obj => obj.includes("P")).length - 1;
	var lastIdx = ecctcList.length - 1;
	var str = "완료";
	var lnkEsntlId = "";
	var drftDe = "";
	var dummyData = {};

	if (lastPlanIdx != -1) {
		if (ecctcIdx <= lastPlanIdx) {
			var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[lastPlanIdx] + "List").getAllJSON();
			if (grdData.find(obj => obj.ectccId == " ")) {
				var dltData = $p.getComponentById("dltEctccLnk" + ecctcList[lastPlanIdx] + "List");
				dltData.removeRow(0);

				str = "계획" + str;
				lnkEsntlId = dmaPlanCnstrc.getJSON().planEsntlId;
				for (var idx = 0; idx <= lastPlanIdx; idx++) {
					grdData = $p.getComponentById("grdEctccLnk" + ecctcList[idx] + "List").getAllJSON();
					if (grdData.length) {
						var data = grdData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max, 0);
						drftDe = drftDe > data ? drft : data;
					}
				}
				dummyData.ecsBsnsPrgsDivCd = ecctcList[lastPlanIdx];
			} else {
				return;
			}
		} else {
			var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[lastIdx] + "List").getAllJSON();
			if (grdData.find(obj => obj.ectccId == " ")) {
				var dltData = $p.getComponentById("dltEctccLnk" + ecctcList[lastIdx] + "List");
				dltData.removeRow(0);

				str = "건설" + str;
				lnkEsntlId = dmaPlanCnstrc.getJSON().cnstrcEsntlId;
				for (var idx = lastPlanIdx + 1; idx <= lastIdx; idx++) {
					grdData = $p.getComponentById("grdEctccLnk" + ecctcList[idx] + "List").getAllJSON();
					if (grdData.length) {
						var data = grdData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max, 0);
						drftDe = drftDe > data ? drft : data;
					}
				}
				dummyData.ecsBsnsPrgsDivCd = ecctcList[lastIdx];
			} else {
				return;
			}
		}
	} else {
		var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[lastIdx] + "List").getAllJSON();
		if (grdData.find(obj => obj.ectccId == " ")) {
			var dltData = $p.getComponentById("dltEctccLnk" + ecctcList[lastIdx] + "List");
			dltData.removeRow(0);

			str = "폐기" + str;
			lnkEsntlId = dmaSetcscDsusePrcsDtlHist.getJSON().dsuseEsntlId;
			for (var idx = 0; idx <= lastIdx; idx++) {
				grdData = $p.getComponentById("grdEctccLnk" + ecctcList[idx] + "List").getAllJSON();
				if (grdData.length) {
					var data = grdData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max, 0);
					drftDe = drftDe > data ? drftDe : data;
				}
			}
			dummyData.ecsBsnsPrgsDivCd = ecctcList[lastIdx];
		} else {
			return;
		}
	}

	dummyData.ectccId = " ";
	dummyData.ectccTit = str;
	dummyData.drftDe = drftDe;
	dummyData.lnkEsntlId = lnkEsntlId;
	dummyData.rowStatus = "C";

	var newIndex = dltData.insertRow();
	dltData.setRowJSON(newIndex, dummyData, true);
};

